  5→
  6→import { useQuery, useMutation, useQueryClient, keepPreviousData } from "@tanstack/react-query";
  7→import { useMemo } from "react";
  8→import { produce } from "immer";
  9→import {
 10→  WorkspaceService,
 11→  type WorkspaceGitInfo,
 12→  type ManifestResponse,
 13→} from "./workspace.service";
 14→import { RepoService } from "@/features/repository/api/repository.service";
 15→import { queryKeys } from "@/shared/api/queryKeys";
 16→import type { Workspace, RepoGroup, DiffStats } from "../types";
 17→import type { PRStatus } from "@/shared/types";
 18→import { createOptimisticWorkspace } from "../lib/workspace.utils";
 19→import { track } from "@/platform/analytics";
 20→
 21→/**
 22→ * Fetch workspaces grouped by repository.
 23→ *
 24→ * Event-driven invalidation handles freshness — no polling needed.
 25→ * Refetches on mount and window focus for reconciliation.
 26→ */
 27→export function useWorkspacesByRepo(state: string = "ready,initializing") {
 28→  return useQuery({
 29→    queryKey: queryKeys.workspaces.byRepo(state),
 30→    queryFn: () => WorkspaceService.fetchByRepo(state),
 31→    staleTime: 5000,
 32→    refetchOnWindowFocus: "always",
 33→  });
 34→}
 35→
 36→/**
 37→ * Fetch global stats.
 38→ *
 39→ * Explicit invalidation + focus reconciliation — no polling.
 40→ */
 41→export function useStats() {
 42→  return useQuery({
 43→    queryKey: queryKeys.stats.all,
 44→    queryFn: () => RepoService.fetchStats(),
 45→    staleTime: 15_000,
 46→    refetchOnWindowFocus: "always",
 47→  });
 48→}
 49→
 50→/**
 51→ * Fetch diff stats for a specific workspace
 52→ * Conditionally polls only when workspace is actively working.
 53→ *
 54→ * When `isWatched` is true (file watcher active via notify crate),
 55→ * polling is disabled — cache invalidation comes from fs:changed events.
 56→ * Falls back to 5s polling when not watched.
 57→ *
 58→ * IMPORTANT: Requires workspaceState === "ready" to avoid fetching diffs
 59→ * against incomplete worktrees during initialization. Running git diff on
 60→ * an initializing worktree produces garbage (e.g. +500K/-1M) that gets
 61→ * cached for 30s, persisting as phantom diffs even after the workspace
 62→ * becomes ready. Guard here, not in the UI.
 63→ */
 64→export function useDiffStats(
 65→  workspaceId: string | null,
 66→  sessionStatus?: string | null,
 67→  workspace?: WorkspaceGitInfo,
 68→  isWatched: boolean = false,
 69→  workspaceState?: string | null
 70→) {
 71→  return useQuery({
 72→    queryKey: queryKeys.workspaces.diffStats(workspaceId || ""),
 73→    queryFn: () => WorkspaceService.fetchDiffStats(workspaceId!, workspace),
 74→    enabled: !!workspaceId && workspaceState === "ready",
 75→    staleTime: 30000,
 76→    // Events handle invalidation when watched; fall back to polling otherwise
 77→    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
 78→    refetchOnMount: "always",
 79→    refetchOnWindowFocus: true,
 80→  });
 81→}
 82→
 83→/**
 84→ * Fetch diff stats for all sidebar workspaces in bulk.
 85→ *
 86→ * Replaces per-item useDiffStats() in the sidebar (N hooks → 1 query).
 87→ * - Initial load: fetches ALL ready workspaces in parallel batches of 15
 88→ * - Polling: only re-fetches workspaces with session_status === "working" (5s)
 89→ * - Idle: no polling (staleTime 30s, refetch on window focus)
 90→ * - On workspace list change: seeds from per-workspace cache, fetches only missing/working
 91→ *
 92→ * Guard: state === "ready" — initializing worktrees have incomplete git state
 93→ * (missing HEAD, partial index → garbage diffs like +500K/-1M). Setup script
 94→ * diffs are fine — .gitignore handles them, and `git checkout -- .` in the
 95→ * init pipeline resets any tracked-file mutations from bun install.
 96→ */
 97→export function useBulkDiffStats(repoGroups: RepoGroup[]) {
 98→  const queryClient = useQueryClient();
 99→
100→  const workspaceInfoMap = useMemo(() => {
101→    const map = new Map<string, WorkspaceGitInfo>();
102→    repoGroups.forEach((g) => {
103→      g.workspaces.forEach((w) => {
104→        if (w.state !== "ready") return;
105→        map.set(w.id, {
106→          root_path: w.root_path,
107→          slug: w.slug,
108→          workspace_path: w.workspace_path,
109→          git_target_branch: w.git_target_branch ?? undefined,
110→          git_default_branch: w.git_default_branch,
111→        });
112→      });
113→    });
114→    return map;
115→  }, [repoGroups]);
116→
117→  // Stable, de-duplicated IDs for query key — only ready workspaces.
118→  const workspaceIds = useMemo(() => {
119→    const ids = repoGroups.flatMap((g) =>
120→      g.workspaces.filter((w) => w.state === "ready").map((w) => w.id)
121→    );
122→    return Array.from(new Set(ids)).sort();
123→  }, [repoGroups]);
124→
125→  // IDs of workspaces with active sessions — only these need polling.
126→  const workingIds = useMemo(() => {
127→    return repoGroups
128→      .flatMap((g) => g.workspaces)
129→      .filter((w) => w.state === "ready" && w.session_status === "working")
130→      .map((w) => w.id);
131→  }, [repoGroups]);
132→
133→  const hasWorkingWorkspaces = workingIds.length > 0;
134→
135→  return useQuery({
136→    queryKey: ["bulk-diff-stats", workspaceIds],
137→    enabled: workspaceIds.length > 0,
138→    staleTime: 30_000,
139→    placeholderData: keepPreviousData,
140→    refetchInterval: hasWorkingWorkspaces ? 5000 : false,
141→    refetchOnMount: "always",
142→    refetchOnWindowFocus: true,
143→    queryFn: async () => {
144→      // Seed from per-workspace cache for workspaces we already have data for
145→      const results: Record<string, DiffStats> = {};
146→      for (const id of workspaceIds) {
147→        const cached = queryClient.getQueryData<DiffStats>(queryKeys.workspaces.diffStats(id));
148→        if (cached) results[id] = cached;
149→      }
150→
151→      // Fetch: missing workspaces + working workspaces (need fresh data)
152→      const missingIds = workspaceIds.filter((id) => !(id in results));
153→      const idsToFetch = [...new Set([...missingIds, ...workingIds])];
154→
155→      if (idsToFetch.length === 0) return results;
156→
157→      // Parallel batches of 15 — balances throughput vs resource pressure
158→      const BATCH_SIZE = 15;
159→      for (let i = 0; i < idsToFetch.length; i += BATCH_SIZE) {
160→        const batch = idsToFetch.slice(i, i + BATCH_SIZE);
161→        const settled = await Promise.allSettled(
162→          batch.map((id) => WorkspaceService.fetchDiffStats(id, workspaceInfoMap.get(id)))
163→        );
164→
165→        batch.forEach((id, j) => {
166→          if (settled[j].status === "fulfilled") {
167→            results[id] = settled[j].value;
168→            queryClient.setQueryData(queryKeys.workspaces.diffStats(id), settled[j].value);
169→          }
170→        });
171→      }
172→
173→      return results;
174→    },
175→  });
176→}
177→
178→/**
179→ * Fetch file changes for a workspace
180→ * Conditionally polls only when workspace is actively working.
181→ *
182→ * When `isWatched` is true (file watcher active via notify crate),
183→ * polling is disabled — cache invalidation comes from fs:changed events.
184→ * Falls back to 5s polling when not watched.
185→ *
186→ * IMPORTANT: Requires workspaceState === "ready" — same guard as useDiffStats.
187→ * See useDiffStats comment for the full explanation of the phantom diff race.
188→ */
189→export function useFileChanges(
190→  workspaceId: string | null,
191→  sessionStatus?: string | null,
192→  workspace?: WorkspaceGitInfo,
193→  isWatched: boolean = false,
194→  workspaceState?: string | null
195→) {
196→  return useQuery({
197→    queryKey: queryKeys.workspaces.diffFiles(workspaceId || ""),
198→    queryFn: async () => {
199→      const result = await WorkspaceService.fetchDiffFiles(workspaceId!, workspace);
200→      return {
201→        files: result.files || [],
202→        truncated: result.truncated ?? false,
203→        totalCount: result.totalCount ?? result.files?.length ?? 0,
204→      };
205→    },
206→    enabled: !!workspaceId && workspaceState === "ready",
207→    staleTime: 30000,
208→    // Events handle invalidation when watched; fall back to polling otherwise
209→    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
210→    refetchOnMount: "always",
211→    refetchOnWindowFocus: true,
212→  });
213→}
214→
215→/**
216→ * Fetch uncommitted files for a workspace (HEAD → workdir).
217→ * Tauri IPC only — polls when workspace is actively working.
218→ *
219→ * IMPORTANT: Requires workspaceState === "ready" — same guard as useDiffStats.
220→ */
221→export function useUncommittedFiles(
222→  workspaceId: string | null,
223→  sessionStatus?: string | null,
224→  workspace?: WorkspaceGitInfo,
225→  workspaceState?: string | null
226→) {
227→  return useQuery({
228→    queryKey: queryKeys.workspaces.uncommittedFiles(workspaceId || ""),
229→    queryFn: () => WorkspaceService.fetchUncommittedFiles(workspace),
230→    enabled: !!workspaceId && workspaceState === "ready",
231→    staleTime: 30000,
232→    refetchInterval: sessionStatus === "working" ? 5000 : false,
233→    refetchOnMount: "always",
234→    refetchOnWindowFocus: true,
235→  });
236→}
237→
238→/**
239→ * Fetch last-turn files for a workspace (checkpoint → workdir).
240→ * Tauri IPC only — polls when workspace is actively working.
241→ *
242→ * IMPORTANT: Requires workspaceState === "ready" — same guard as useDiffStats.
243→ */
244→export function useLastTurnFiles(
245→  workspaceId: string | null,
246→  sessionId: string | null | undefined,
247→  sessionStatus?: string | null,
248→  workspace?: WorkspaceGitInfo,
249→  workspaceState?: string | null
250→) {
251→  return useQuery({
252→    queryKey: queryKeys.workspaces.lastTurnFiles(workspaceId || "", sessionId || undefined),
253→    queryFn: () => WorkspaceService.fetchLastTurnFiles(workspace, sessionId || undefined),
254→    enabled: !!workspaceId && !!sessionId && workspaceState === "ready",
255→    staleTime: 30000,
256→    refetchInterval: sessionStatus === "working" ? 5000 : false,
257→    refetchOnMount: "always",
258→    refetchOnWindowFocus: true,
259→  });
260→}
261→
262→/**
263→ * Check GitHub CLI availability and auth status.
264→ * Cached with 5-minute staleTime — rarely changes during a session.
265→ * Gates usePRStatus to avoid wasted gh calls when CLI is missing or unauthenticated.
266→ */
267→export function useGhStatus() {
268→  return useQuery({
269→    queryKey: queryKeys.github.ghStatus,
270→    queryFn: () => WorkspaceService.fetchGhStatus(),
271→    staleTime: 5 * 60 * 1000, // 5 minutes
272→    refetchOnWindowFocus: false,
273→  });
274→}
275→
276→/**
277→ * Fetch PR status for a workspace.
278→ *
279→ * Gated on gh CLI being installed + authenticated (like Codex).
280→ * Polls every 30s while agent is working (to detect PR creation),
281→ * 60s while CI is pending post-session (CI runs 2-15min after push),
282→ * stops polling otherwise. Auto-refetched on session completion
283→ * via useSessionEvents invalidation.
284→ */
285→export function usePRStatus(
286→  workspaceId: string | null,
287→  options?: { ghInstalled?: boolean; ghAuthenticated?: boolean; sessionStatus?: string }
288→) {
289→  const { ghInstalled = true, ghAuthenticated = true, sessionStatus } = options ?? {};
290→  return useQuery({
291→    queryKey: queryKeys.workspaces.prStatus(workspaceId || ""),
292→    queryFn: () => WorkspaceService.fetchPRStatus(workspaceId!),
293→    enabled: !!workspaceId && ghInstalled && ghAuthenticated,
294→    staleTime: 10_000,
295→    refetchInterval: (query) => {
296→      // While agent is working: poll every 30s to detect PR creation/updates.
297→      if (sessionStatus === "working") return 30_000;
298→
299→      // After agent stops: CI checks typically run 2-15min. Poll every 60s
300→      // while CI is pending so the user sees updates without manual refresh.
301→      const data = query.state.data as PRStatus | null | undefined;
302→      if (data?.has_pr && data?.ci_status === "pending") return 60_000;
303→
304→      // No PR or CI resolved: stop polling. Window focus refetch handles edge cases.
305→      return false;
306→    },
307→    refetchOnWindowFocus: true,
308→  });
309→}
310→
311→/**
312→ * Fetch specific file diff
313→ */
314→export function useFileDiff(
315→  workspaceId: string | null,
316→  filePath: string | null,
317→  workspace?: WorkspaceGitInfo
318→) {
319→  return useQuery({
320→    queryKey: queryKeys.workspaces.diffFile(workspaceId || "", filePath || ""),
321→    queryFn: async () => {
322→      const result = await WorkspaceService.fetchFileDiff(workspaceId!, filePath!, workspace);
323→      return result;
324→    },
325→    enabled: !!workspaceId && !!filePath,
326→    staleTime: 10000, // Cache for 10s since diffs are expensive
327→  });
328→}
329→
330→/**
331→ * Create workspace mutation with optimistic update.
332→ *
333→ * Flow:
334→ * 1. User clicks "+" → placeholder workspace appears instantly in sidebar
335→ * 2. Backend creates workspace (state = "initializing"), returns it
336→ * 3. onSuccess replaces placeholder with real data, triggers refetch
337→ * 4. Workspace progress events + terminal invalidation catch the ready transition
338→ */
339→export function useCreateWorkspace() {
340→  const queryClient = useQueryClient();
341→  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
342→
343→  return useMutation({
344→    mutationFn: (repositoryId: string) => WorkspaceService.create(repositoryId),
345→
346→    onMutate: async (repositoryId: string) => {
347→      await queryClient.cancelQueries({ queryKey });
348→
349→      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
350→
351→      // Inject a placeholder workspace into the matching repo group
352→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
353→        if (!old) return old;
354→        return produce(old, (draft) => {
355→          const repoGroup = draft.find((g) => g.repo_id === repositoryId);
356→          if (repoGroup) {
357→            repoGroup.workspaces.unshift(
358→              createOptimisticWorkspace(repositoryId, repoGroup.repo_name)
359→            );
360→          }
361→        });
362→      });
363→
364→      return { previousData };
365→    },
366→
367→    onError: (_err, _repositoryId, context) => {
368→      if (context?.previousData) {
369→        queryClient.setQueryData(queryKey, context.previousData);
370→      }
371→    },
372→
373→    onSuccess: (_data, repositoryId) => {
374→      track("workspace_created", { repository_id: repositoryId });
375→    },
376→
377→    onSettled: () => {
378→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
379→    },
380→  });
381→}
382→
383→/**
384→ * Fetch available branches for a workspace/repo.
385→ * Uses Tauri IPC (fast, libgit2). Returns [] gracefully in browser/Storybook.
386→ */
387→export function useBranches(workspacePath: string | null) {
388→  return useQuery({
389→    queryKey: ["branches", workspacePath],
390→    queryFn: async () => {
391→      const { isTauriAvailable } = await import("@/platform/tauri/invoke");
392→      if (!isTauriAvailable()) {
393→        return [];
394→      }
395→      const { gitListBranches } = await import("@/platform/tauri/git");
396→      return await gitListBranches(workspacePath!);
397→    },
398→    enabled: !!workspacePath,
399→    staleTime: 30_000,
400→  });
401→}
402→
403→/**
404→ * Archive workspace mutation with optimistic update
405→ *
406→ * Flow:
407→ * 1. User clicks archive → UI updates IMMEDIATELY (workspace removed from list)
408→ * 2. HTTP request sent in background
409→ * 3. Success: Cache already correct, refetch confirms
410→ * 4. Error: Rollback to previous state, show error
411→ */
412→export function useArchiveWorkspace() {
413→  const queryClient = useQueryClient();
414→  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
415→
416→  return useMutation({
417→    mutationFn: (workspaceId: string) => WorkspaceService.archive(workspaceId),
418→
419→    // Optimistic update: Remove workspace from UI immediately
420→    onMutate: async (workspaceId: string) => {
421→      // Cancel any outgoing refetches (so they don't overwrite our optimistic update)
422→      await queryClient.cancelQueries({ queryKey });
423→
424→      // Snapshot the previous value
425→      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
426→
427→      // Optimistically remove the workspace from the list
428→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
429→        if (!old) return old;
430→        return produce(old, (draft) => {
431→          for (const repo of draft) {
432→            const index = repo.workspaces.findIndex((w) => w.id === workspaceId);
433→            if (index !== -1) {
434→              repo.workspaces.splice(index, 1);
435→              break;
436→            }
437→          }
438→        });
439→      });
440→
441→      // Return context with the previous value for rollback
442→      return { previousData };
443→    },
444→
445→    // If mutation fails, roll back to the previous value
446→    onError: (_err, _workspaceId, context) => {
447→      if (context?.previousData) {
448→        queryClient.setQueryData(queryKey, context.previousData);
449→      }
450→    },
451→
452→    onSuccess: (_data, workspaceId) => {
453→      track("workspace_archived", { workspace_id: workspaceId });
454→    },
455→
456→    // Always refetch after error or success to ensure consistency
457→    onSettled: () => {
458→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
459→    },
460→  });
461→}
462→
463→/**
464→ * Unarchive workspace mutation — restores state to "ready".
465→ * Used by the undo toast after archiving.
466→ */
467→export function useUnarchiveWorkspace() {
468→  const queryClient = useQueryClient();
469→
470→  return useMutation({
471→    mutationFn: (workspaceId: string) => WorkspaceService.update(workspaceId, { state: "ready" }),
472→    onSuccess: (_data, workspaceId) => {
473→      track("workspace_unarchived", { workspace_id: workspaceId });
474→    },
475→    onSettled: () => {
476→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
477→    },
478→  });
479→}
480→
481→/**
482→ * Fetch system prompt for a workspace
483→ */
484→export function useSystemPrompt(workspaceId: string | null) {
485→  return useQuery({
486→    queryKey: queryKeys.workspaces.systemPrompt(workspaceId || ""),
487→    queryFn: async () => {
488→      const result = await WorkspaceService.fetchSystemPrompt(workspaceId!);
489→      return result.system_prompt || "";
490→    },
491→    enabled: !!workspaceId,
492→    staleTime: 30000, // System prompts don't change often
493→  });
494→}
495→
496→/**
497→ * Update system prompt mutation with optimistic update
498→ */
499→export function useUpdateSystemPrompt() {
500→  const queryClient = useQueryClient();
501→
502→  return useMutation({
503→    mutationFn: ({ workspaceId, systemPrompt }: { workspaceId: string; systemPrompt: string }) =>
504→      WorkspaceService.updateSystemPrompt(workspaceId, systemPrompt),
505→
506→    // Optimistic update: Show new prompt immediately
507→    onMutate: async ({ workspaceId, systemPrompt }) => {
508→      await queryClient.cancelQueries({
509→        queryKey: queryKeys.workspaces.systemPrompt(workspaceId),
510→      });
511→
512→      const previousPrompt = queryClient.getQueryData<string>(
513→        queryKeys.workspaces.systemPrompt(workspaceId)
514→      );
515→
516→      queryClient.setQueryData(queryKeys.workspaces.systemPrompt(workspaceId), systemPrompt);
517→
518→      return { previousPrompt };
519→    },
520→
521→    onError: (_err, variables, context) => {
522→      if (context?.previousPrompt !== undefined) {
523→        queryClient.setQueryData(
524→          queryKeys.workspaces.systemPrompt(variables.workspaceId),
525→          context.previousPrompt
526→        );
527→      }
528→    },
529→
530→    onSettled: (_, __, variables) => {
531→      queryClient.invalidateQueries({
532→        queryKey: queryKeys.workspaces.systemPrompt(variables.workspaceId),
533→      });
534→    },
535→  });
536→}
537→
538→/**
539→ * Fetch opendevs.json manifest + normalized tasks for a workspace.
540→ * Manifest doesn't change during a session — staleTime: Infinity.
541→ */
542→export function useManifestTasks(workspaceId: string | null) {
543→  return useQuery({
544→    queryKey: queryKeys.workspaces.manifest(workspaceId || ""),
545→    queryFn: () => WorkspaceService.fetchManifest(workspaceId!),
546→    enabled: !!workspaceId,
547→    staleTime: Infinity,
548→  });
549→}
550→
551→/**
552→ * Retry failed setup for a workspace.
553→ * Invalidates workspace queries to refresh setup_status.
554→ */
555→export function useRetrySetup() {
556→  const queryClient = useQueryClient();
557→
558→  return useMutation({
559→    mutationFn: (workspaceId: string) => WorkspaceService.retrySetup(workspaceId),
560→    onSettled: () => {
561→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
562→    },
563→  });
564→}
