export function useManifestTasks(workspaceId: string | null) {
  return useQuery({
    queryKey: queryKeys.workspaces.manifest(workspaceId || ""),
    queryFn: () => WorkspaceService.fetchManifest(workspaceId!),
    enabled: !!workspaceId,
    staleTime: Infinity,
