  1→/**
  2→ * Workspace Layout Hook
  3→ * Provides workspace-specific layout state with proper store synchronization
  4→ *
  5→ * This hook eliminates the bidirectional sync anti-pattern by:
  6→ * 1. Reading layout state directly from the store
  7→ * 2. Providing stable callbacks that update the store
  8→ * 3. Keeping transient diff data local (not persisted)
  9→ *
 10→ * Usage:
 11→ * ```typescript
 12→ * const {
 13→ *   rightSideTab,
 14→ *   rightPanelTab,
 15→ *   selectedFilePath,
 16→ *   setRightSideTab,
 17→ *   setRightPanelTab,
 18→ *   setSelectedFilePath,
 19→ * } = useWorkspaceLayout(workspaceId);
 20→ * ```
 21→ */
 22→
 23→import { useCallback } from "react";
 24→import { useShallow } from "zustand/react/shallow";
 25→import {
 26→  useWorkspaceLayoutStore,
 27→  workspaceLayoutActions,
 28→  defaultLayout,
 29→} from "../store/workspaceLayoutStore";
 30→import type { RightPanelTab, RightSideTab } from "../store/workspaceLayoutStore";
 31→
 32→interface UseWorkspaceLayoutResult {
 33→  /** Current code panel tab (changes, files) */
 34→  rightPanelTab: RightPanelTab;
 35→  /** Current right side panel tab (code, config, terminal, design, browser) */
 36→  rightSideTab: RightSideTab;
 37→  /** Currently selected file path (for highlighting in tree) */
 38→  selectedFilePath: string | null;
 39→  /** Whether sidebar is collapsed */
 40→  sidebarCollapsed: boolean;
 41→  /** Whether chat panel is collapsed */
 42→  chatPanelCollapsed: boolean;
 43→  /** Whether right panel is collapsed */
 44→  rightPanelCollapsed: boolean;
 45→
 46→  /** Set the active right panel tab */
 47→  setRightPanelTab: (tab: RightPanelTab) => void;
 48→  /** Set the active right side panel tab */
 49→  setRightSideTab: (tab: RightSideTab) => void;
 50→  /** Set selected file path */
 51→  setSelectedFilePath: (path: string | null, source?: "changes" | "files") => void;
 52→  /** Set sidebar collapsed state */
 53→  setSidebarCollapsed: (collapsed: boolean) => void;
 54→  /** Set chat panel collapsed state */
 55→  setChatPanelCollapsed: (collapsed: boolean) => void;
 56→  /** Set right panel collapsed state */
 57→  setRightPanelCollapsed: (collapsed: boolean) => void;
 58→  /** Update multiple layout properties at once */
 59→  updateLayout: (updates: {
 60→    rightPanelTab?: RightPanelTab;
 61→    rightSideTab?: RightSideTab;
 62→    selectedFilePath?: string | null;
 63→    sidebarCollapsed?: boolean;
 64→  }) => void;
 65→}
 66→
 67→export function useWorkspaceLayout(workspaceId: string | null): UseWorkspaceLayoutResult {
 68→  // Subscribe directly to store state - this triggers re-renders when layout changes.
 69→  // useShallow prevents re-renders when setLayout creates a new object via spread
 70→  // but no field values actually changed.
 71→  const layout = useWorkspaceLayoutStore(
 72→    useShallow((state) =>
 73→      workspaceId ? (state.layouts[workspaceId] ?? defaultLayout) : defaultLayout
 74→    )
 75→  );
 76→  // Use stable module-level actions instead of subscribing to store actions via selectors.
 77→  // This prevents unstable references from cascading through useCallback/useEffect chains.
 78→  const { setLayout } = workspaceLayoutActions;
 79→
 80→  // Stable callbacks - only depend on workspaceId (setLayout is module-level stable)
 81→  const setRightPanelTab = useCallback(
 82→    (tab: RightPanelTab) => {
 83→      if (workspaceId) {
 84→        setLayout(workspaceId, { activeRightTab: tab });
 85→      }
 86→    },
 87→    [workspaceId, setLayout]
 88→  );
 89→
 90→  const setRightSideTab = useCallback(
 91→    (tab: RightSideTab) => {
 92→      if (workspaceId) {
 93→        setLayout(workspaceId, { activeRightSideTab: tab });
 94→      }
 95→    },
 96→    [workspaceId, setLayout]
 97→  );
 98→
 99→  const setSelectedFilePath = useCallback(
100→    (path: string | null, source: "changes" | "files" = "changes") => {
101→      if (workspaceId) {
102→        setLayout(workspaceId, {
103→          selectedFile: path ? { path, source } : null,
104→        });
105→      }
106→    },
107→    [workspaceId, setLayout]
108→  );
109→
110→  const setSidebarCollapsed = useCallback(
111→    (collapsed: boolean) => {
112→      if (workspaceId) {
113→        setLayout(workspaceId, { sidebarCollapsed: collapsed });
114→      }
115→    },
116→    [workspaceId, setLayout]
117→  );
118→
119→  const setChatPanelCollapsed = useCallback(
120→    (collapsed: boolean) => {
121→      if (workspaceId) {
122→        setLayout(workspaceId, { chatPanelCollapsed: collapsed });
123→      }
124→    },
125→    [workspaceId, setLayout]
126→  );
127→
128→  const setRightPanelCollapsed = useCallback(
129→    (collapsed: boolean) => {
130→      if (workspaceId) {
131→        setLayout(workspaceId, { rightPanelCollapsed: collapsed });
132→      }
133→    },
134→    [workspaceId, setLayout]
135→  );
136→
137→  const updateLayout = useCallback(
138→    (updates: {
139→      rightPanelTab?: RightPanelTab;
140→      rightSideTab?: RightSideTab;
141→      selectedFilePath?: string | null;
142→      sidebarCollapsed?: boolean;
143→    }) => {
144→      if (!workspaceId) return;
145→
146→      const layoutUpdates: Parameters<typeof setLayout>[1] = {};
147→
148→      if (updates.rightPanelTab !== undefined) {
149→        layoutUpdates.activeRightTab = updates.rightPanelTab;
150→      }
151→      if (updates.rightSideTab !== undefined) {
152→        layoutUpdates.activeRightSideTab = updates.rightSideTab;
153→      }
154→      if (updates.selectedFilePath !== undefined) {
155→        layoutUpdates.selectedFile = updates.selectedFilePath
156→          ? { path: updates.selectedFilePath, source: "changes" }
157→          : null;
158→      }
159→      if (updates.sidebarCollapsed !== undefined) {
160→        layoutUpdates.sidebarCollapsed = updates.sidebarCollapsed;
161→      }
162→
163→      setLayout(workspaceId, layoutUpdates);
164→    },
165→    [workspaceId, setLayout]
166→  );
167→
168→  const normalizedRightPanelTab =
169→    layout.activeRightTab === "files" ? "files" : ("changes" as RightPanelTab);
170→
171→  return {
172→    // State (derived from store)
173→    rightPanelTab: normalizedRightPanelTab,
174→    rightSideTab: layout.activeRightSideTab ?? defaultLayout.activeRightSideTab,
175→    selectedFilePath: layout.selectedFile?.path ?? null,
176→    sidebarCollapsed: layout.sidebarCollapsed,
177→    chatPanelCollapsed: layout.chatPanelCollapsed ?? false,
178→    rightPanelCollapsed: layout.rightPanelCollapsed ?? false,
179→
180→    // Stable callbacks
181→    setRightPanelTab,
182→    setRightSideTab,
183→    setSelectedFilePath,
184→    setSidebarCollapsed,
185→    setChatPanelCollapsed,
186→    setRightPanelCollapsed,
187→    updateLayout,
