  1→/**
  2→ * PR View State -- derives a single discriminated union from raw PR + GH CLI status.
  3→ *
  4→ * This is the ONLY place that interprets PRStatus into what the UI should show.
  5→ * The priority ordering is explicit: earlier checks shadow later ones.
  6→ *
  7→ * Pure function. No React. Trivially testable.
  8→ */
  9→
 10→import type { PRStatus, GhCliStatus } from "@/shared/types";
 11→
 12→/**
 13→ * Discriminated union of all possible PR action states.
 14→ * Each variant carries only the data its rendering path needs.
 15→ *
 16→ * Priority order (highest to lowest):
 17→ *   1. gh CLI unavailable (blocks everything)
 18→ *   2. error (GitHub unreachable — timeout or network failure)
 19→ *   3. no PR (initial state)
 20→ *   4. merged (terminal)
 21→ *   5. closed (terminal — not merged)
 22→ *   6. conflicts (must resolve before anything else)
 23→ *   7. CI failing (fixable, blocks merge)
 24→ *   8. changes requested (reviewer feedback pending)
 25→ *   9. CI pending (waiting, no action)
 26→ *  10. ready to merge (all green)
 27→ *  11. awaiting review (CI passed, needs review)
 28→ */
 29→export type PRActionState =
 30→  | { type: "gh_unavailable"; reason: "not_installed" | "not_authenticated" }
 31→  | { type: "error"; reason: "timeout" | "network" }
 32→  | { type: "no_pr" }
 33→  | { type: "merged"; prNumber: number; prUrl: string }
 34→  | { type: "closed"; prNumber: number; prUrl: string }
 35→  | { type: "conflicts"; prNumber: number; prUrl: string }
 36→  | { type: "ci_failing"; prNumber: number; prUrl: string }
 37→  | { type: "changes_requested"; prNumber: number; prUrl: string }
 38→  | { type: "ci_pending"; prNumber: number; prUrl: string }
 39→  | { type: "ready_to_merge"; prNumber: number; prUrl: string; targetBranch: string }
 40→  | { type: "awaiting_review"; prNumber: number; prUrl: string };
 41→
 42→/**
 43→ * Collapses PRStatus + GhCliStatus into a single discriminated state.
 44→ * The priority ordering ensures that when multiple flags are true
 45→ * (e.g., conflicts + CI failing), only the highest-priority state wins.
 46→ */
 47→export function derivePRActionState(
 48→  prStatus: PRStatus | null,
 49→  ghStatus: GhCliStatus | null | undefined,
 50→  targetBranch: string,
 51→): PRActionState {
 52→  // gh CLI gates everything
 53→  if (ghStatus && !ghStatus.isInstalled) {
 54→    return { type: "gh_unavailable", reason: "not_installed" };
 55→  }
 56→  if (ghStatus && ghStatus.isInstalled && !ghStatus.isAuthenticated) {
 57→    return { type: "gh_unavailable", reason: "not_authenticated" };
 58→  }
 59→
 60→  // gh CLI errors from the PR status endpoint — can arrive during the ghStatus
